/**
 * Import exercises.json → Supabase
 *
 * Usage: node scripts/import-exercises.mjs
 *
 * Reads exercises.json (generated by scrape-superphysique.mjs),
 * normalises the data, then upserts into the exercises table.
 */

import { createClient } from '@supabase/supabase-js'
import { readFileSync } from 'fs'
import { resolve, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dir = dirname(fileURLToPath(import.meta.url))

const envPath = resolve(__dir, '../.env.seed')
const env = Object.fromEntries(
  readFileSync(envPath, 'utf8')
    .split('\n').filter(l => l && !l.startsWith('#'))
    .map(l => { const [k, ...v] = l.split('='); return [k.trim(), v.join('=').trim()] })
)

const supabase = createClient(env.SUPABASE_URL, env.SUPABASE_SERVICE_ROLE_KEY, {
  auth: { autoRefreshToken: false, persistSession: false },
})

const LEVEL_MAP = { base: 'base', advanced: 'advanced', finishing: 'finishing' }
const SIDE_MAP  = { anterior: 'anterior', posterior: 'posterior' }

const raw = JSON.parse(readFileSync(resolve(__dir, '../exercises.json'), 'utf8'))

const rows = raw
  .filter(e => e.name && e.name.trim())
  .map(e => ({
    name:                 e.name.trim(),
    muscle_group:         e.muscle_group || 'Inconnu',
    equipment:            e.equipment    || null,
    default_rest_seconds: e.default_rest_seconds || 90,
    joint_notes:          e.joint_notes  || null,
    description:          e.description  || null,
    video_url:            e.video_url    || null,
    level:                LEVEL_MAP[e.level]       ?? 'base',
    muscle_side:          SIDE_MAP[e.muscle_side]  ?? 'anterior',
  }))

console.log(`\nImporting ${rows.length} exercises...`)

const CHUNK = 50
for (let i = 0; i < rows.length; i += CHUNK) {
  const chunk = rows.slice(i, i + CHUNK)
  const { error } = await supabase.from('exercises').upsert(chunk, { onConflict: 'name' })
  if (error) { console.error(`❌ Chunk ${i}–${i + CHUNK}:`, error.message); continue }
  console.log(`  ✓ ${i + 1}–${Math.min(i + CHUNK, rows.length)}`)
}

console.log('\n✅ Import terminé')
